import React, { useEffect, useState } from "react";

function App() {
  const [tasks, setTasks] = useState([]);
  const [loaded, setLoaded] = useState(false); // 👈 важно

  // загрузка данных
  useEffect(() => {
    const savedTasks = localStorage.getItem("tasks");

    if (savedTasks) {
      setTasks(JSON.parse(savedTasks));
      setLoaded(true);
    } else {
      fetch("https://jsonplaceholder.typicode.com/todos")
        .then(res => res.json())
        .then(data => {
          const formatted = data.slice(0, 20).map(item => ({
            id: item.id,
            title: item.title,
            description: "Описание отсутствует",
            done: item.completed
          }));

          setTasks(formatted);
          setLoaded(true);
        });
    }
  }, []);

  // сохранение ТОЛЬКО после загрузки
  useEffect(() => {
    if (loaded) {
      localStorage.setItem("tasks", JSON.stringify(tasks));
    }
  }, [tasks, loaded]);

  return (
    <div>
      {/* твои компоненты */}
    </div>
  );
}

export default App;
